import { Request, Response, NextFunction } from 'express';
import { GroupService } from './group.service';
import { createGroupSchema, linkTelegramSchema } from './group.validator';
import { CreateGroupDTO, LinkTelegramDTO } from './group.dto';
import logger from '../../config/logger';

export class GroupController {
  private groupService: GroupService;

  constructor(groupService: GroupService) {
    this.groupService = groupService;
  }

  async createGroup(req: Request, res: Response, next: NextFunction) {
    try {
      const validatedData = createGroupSchema.parse(req.body);
      const createGroupDTO = new CreateGroupDTO(validatedData);
      const group = await this.groupService.createGroup(createGroupDTO);
      logger.info('Group created successfully', { groupId: group.id, requestId: res.locals.requestId });
      res.status(201).json({ success: true, data: group });
    } catch (error) {
      next(error);
    }
  }

  async linkTelegram(req: Request, res: Response, next: NextFunction) {
    try {
      const { id } = req.params;
      const validatedData = linkTelegramSchema.parse(req.body);
      const linkTelegramDTO = new LinkTelegramDTO(id, validatedData.telegramChatId);
      await this.groupService.linkTelegram(linkTelegramDTO);
      logger.info('Telegram linked successfully', { groupId: id, requestId: res.locals.requestId });
      res.status(200).json({ success: true, message: 'Telegram linked successfully' });
    } catch (error) {
      next(error);
    }
  }
}

import { GroupRepository } from './group.repository';
import { CreateGroupDTO, GroupResponseDTO, LinkTelegramDTO } from './group.dto';
import AppError from '../../utils/app-error';

export class GroupService {
  private groupRepository: GroupRepository;

  constructor(groupRepository: GroupRepository) {
    this.groupRepository = groupRepository;
  }

  async createGroup(createGroupDTO: CreateGroupDTO): Promise<GroupResponseDTO> {
    try {
      const group = await this.groupRepository.create(createGroupDTO);
      return new GroupResponseDTO(group);
    } catch (error) {
      throw new AppError('Could not create group', 'GROUP_CREATE_ERROR');
    }
  }

  async linkTelegram(linkTelegramDTO: LinkTelegramDTO): Promise<void> {
    try {
      await this.groupRepository.linkTelegram(linkTelegramDTO.groupId, linkTelegramDTO.telegramChatId);
    } catch (error) {
      throw new AppError('Could not link Telegram Chat', 'TELEGRAM_LINK_ERROR');
    }
  }
}

import { GroupModel } from './group.model';
import { CreateGroupDTO } from './group.dto';

export class GroupRepository {
  async create(createGroupDTO: CreateGroupDTO) {
    const group = new GroupModel(createGroupDTO);
    return await group.save();
  }

  async linkTelegram(groupId: string, telegramChatId: string) {
    const group = await GroupModel.findById(groupId);
    if (!group) throw new Error('Group not found');
    group.telegramChatId = telegramChatId;
    await group.save();
  }
}

import mongoose, { Schema, Document } from 'mongoose';

export interface Group extends Document {
  name: string;
  description: string;
  adminId: mongoose.Types.ObjectId;
  members: mongoose.Types.ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

const GroupSchema: Schema = new Schema({
  name: { type: String, required: true },
  description: { type: String, required: true },
  adminId: { type: mongoose.Types.ObjectId, required: true },
  members: [{ type: mongoose.Types.ObjectId }],
  telegramChatId: { type: String },
  createdAt: { type: Date, default: Date.now },
}, {
  timestamps: true,
});

export const GroupModel = mongoose.model<Group>('Group', GroupSchema);

export class CreateGroupDTO {
  name: string;
  description: string;
  adminId: string;
  members: string[];

  constructor({ name, description, adminId, members }: any) {
    this.name = name;
    this.description = description;
    this.adminId = adminId;
    this.members = members;
  }
}

export class LinkTelegramDTO {
  groupId: string;
  telegramChatId: string;

  constructor(groupId: string, telegramChatId: string) {
    this.groupId = groupId;
    this.telegramChatId = telegramChatId;
  }
}

export class GroupResponseDTO {
  id: string;
  name: string;
  description: string;

  constructor(group: any) {
    this.id = group._id;
    this.name = group.name;
    this.description = group.description;
  }
}

import { z } from 'zod';

export const createGroupSchema = z.object({
  name: z.string().min(1),
  description: z.string().min(1),
  adminId: z.string(),
  members: z.array(z.string())
});

export const linkTelegramSchema = z.object({
  telegramChatId: z.string().min(1)
});
